// ==== equipment_gear icons (armor x4 + trinket x4) ====

// local shape helpers (self-contained, only Painter + sym + P + lighten/darken)
function _gearShield(p, c, cD, cL) {
  for (let y = 3; y <= 12; y++) {
    const t = (y - 3) / 9;
    const w = 4.4 * (1 - t * 0.5) * (y > 9 ? (13 - y) / 3.5 : 1);
    p.hline(8 - w, 7 + w, y, t < 0.45 ? c : cD);
  }
  p.hline(5, 10, 3, cL);
  p.vline(4, 9, 8, lighten(c, 0.18));
}
function _gearRing(p, metal, gem) {
  p.ring(8, 9, 3.3, metal);
  p.ring(8, 9, 2.5, darken(metal, 0.25));
  p.ellipse(8, 5, 1.7, 1.7, gem);
  p.px(8, 5, P.white);
}

// ---- armor -----------------------------------------------------------------
// 重甲：厚重鋼板甲
defineIcon('equip_g_heavy_plate', P.steelD, (p) => {
  for (let y = 3; y <= 13; y++) {
    const t = (y - 3) / 10;
    const w = 5 * (1 - t * 0.22);
    p.hline(8 - w, 7 + w, y, t < 0.45 ? P.steel : P.steelD);
  }
  p.rect(6, 3, 4, 3, P.iron);
  p.hline(3, 12, 7, darken(P.steelD, 0.2));
  p.vline(3, 13, 8, P.steelL);
  p.px(5, 5, P.steelL);
  p.px(10, 9, P.steelL);
});

